export function getCitiesByProvince(code: string): CanonicalCity[] {
  const upper = code.toUpperCase();
  return CANONICAL_CITIES.filter(c => c.province === upper);
}

export function getCityBySlug(provinceCode: string, citySlug: string): CanonicalCity | null {
  const upper = provinceCode.toUpperCase();
  return CANONICAL_CITIES.find(c => c.province === upper && c.slug === citySlug) || null;
}

export function getProvinceByCode(code: string): Province | null {
  return PROVINCES.find(p => p.code === code.toUpperCase()) || null;
}
